1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	
5	const NEWCOMER_FIRST_INSURANCE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 110,
7	  amulet: 66,
8	  staff: 88,
9	  potion: 44,
10	};
11	
12	export type Customer = {
13	  yearsInsured: number;
14	  previousQuotes: number;
15	};
16	
17	export type Item = {
18	  type: string;
19	};
20	
21	export type QuoteInput = {
22	  items: Item[];
23	  customer: Customer;
24	};
25	
26	const premiumForItem = (item: Item): number =>
27	  NEWCOMER_FIRST_INSURANCE_PREMIUM_BY_TYPE[item.type];
28	
29	export const quote = (input: QuoteInput): number => {
30	  const { items } = input;
31	  if (items.length === 0) return PROCESSING_FEE;
32	  return premiumForItem(items[0]) + PROCESSING_FEE;
33	};
