2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office - quote", () => {
6	  // Empty / processing fee
7	  it("empty item list yields premium 5 G (only processing fee)", () => {
8	    expect(quote({ items: [], customer: { yearsInsured: 0, previousQuotes: 0 } })).toBe(5);
9	  });
10	
11	  // Single main item base premiums
12	  it("single plain sword (newcomer, first insurance) yields 115 G (100 base + 10 first + 5 fee)", () => {
13	    expect(
14	      quote({
15	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
16	        customer: { yearsInsured: 0, previousQuotes: 0 },
17	      })
18	    ).toBe(115);
19	  });
20	  it("single plain amulet (newcomer, first insurance) yields 71 G (60 base + 6 first + 5 fee)", () => {
21	    expect(
22	      quote({
23	        items: [{ type: "amulet", material: "steel", enchantment: 0, cursed: false }],
24	        customer: { yearsInsured: 0, previousQuotes: 0 },
25	      })
26	    ).toBe(71);
27	  });
28	  it("single plain staff (newcomer, first insurance) yields 93 G (80 base + 8 first + 5 fee)", () => {
29	    expect(
30	      quote({
31	        items: [{ type: "staff", material: "steel", enchantment: 0, cursed: false }],
32	        customer: { yearsInsured: 0, previousQuotes: 0 },
33	      })
34	    ).toBe(93);
35	  });
36	  it("single plain potion (newcomer, first insurance) yields 49 G (40 base + 4 first + 5 fee)", () => {
37	    expect(
38	      quote({
39	        items: [{ type: "potion", material: "steel", enchantment: 0, cursed: false }],
40	        customer: { yearsInsured: 0, previousQuotes: 0 },
41	      })
42	    ).toBe(49);
43	  });
44	
45	  // Components - building block rule
46	  it("2 runes yields base premium 50 G (25 each, no block)", () => {
47	    expect(
48	      quote({
49	        items: [
50	          { type: "rune", material: "steel", enchantment: 0, cursed: false },
51	          { type: "rune", material: "steel", enchantment: 0, cursed: false },
52	        ],
53	        customer: { yearsInsured: 0, previousQuotes: 0 },
54	      })
55	    ).toBe(60);
56	  });
57	  it.todo("3 runes yields base premium 60 G (block applies)");
58	  it.todo("4 runes yields base premium 100 G (no block - requires exactly 3)");
59	  it.todo("7 runes yields base premium 175 G (one block of 3 + 4 singles)");
60	
61	  // Alike components
62	  it.todo("2 runes + 1 moonstone yields base premium 75 G (different types, no block)");
63	  it.todo("3 runes + 3 moonstones yields base premium 120 G (two separate blocks)");
64	
65	  // Item-specific modifiers: cursed
66	  it.todo("cursed sword (newcomer) yields 165 G (100 base + 50 curse + 10 first + 5 fee)");
67	
68	  // Item-specific modifiers: high enchantment
69	  it.todo("sword with enchantment exactly 5 (newcomer) triggers high-enchantment surcharge");
70	  it.todo("sword with enchantment 4 (newcomer) does not trigger high-enchantment surcharge");
71	
72	  // Modifier scope on multi-item policies
73	  it.todo("policy with cursed sword and plain amulet: curse surcharge applies only to sword's base premium");
74	
75	  // Policy-wide modifiers: loyalty
76	  it.todo("customer with exactly 2 years receives 20% loyalty discount");
77	
78	  // Policy-wide modifiers: follow-up contract
79	  it.todo("customer's second quote receives 15% follow-up discount");
80	
81	  // Rounding
82	  it.todo("premium calculation yielding 197.5 G rounds up to 198 G (in MHPCO's favor)");
83	
84	  // Integration examples
85	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields 165 G");
86	  it.todo("long-standing customer (3 years) second quote, cursed sword enchantment 7 yields 160 G");
87	});
