91	  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G");
92	  it.todo("rune damage 200 G yields payout 100 G");
93	
94	  // Deductible per damage event
95	  it.todo("dragon attack damaging sword (500 G) and amulet (300 G) yields payout 600 G");
96	
97	  // High enchantment threshold
98	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
99	
100	  // Dragon material
