113	  it.todo("sword (cap 2000) after first 1400 G payout: second claim 1500 G yields payout 600 G, remaining cap 0");
114	
115	  // Multiple items of same type
116	  it.todo("policy with two swords: dragon attack on both treats each as separate damage with own deductible");
117	
118	  // Rounding for payout
